import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppView {
  DASHBOARD = 'DASHBOARD',
  PROCEDURES = 'PROCEDURES',
  TRACKING = 'TRACKING',
  CHATBOT = 'CHATBOT',
  APPOINTMENT = 'APPOINTMENT'
}

export interface Procedure {
  id: string;
  title: string;
  category: string;
  description: string;
  estimatedDays: number;
  cost: string;
}

export interface DocumentStatus {
  id: string;
  citizenName: string;
  procedureName: string;
  status: 'PENDING' | 'PROCESSING' | 'COMPLETED' | 'REJECTED';
  submittedDate: string;
  updatedDate: string;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getGeminiChatResponse = async (userMessage: string, history: { role: 'user' | 'model', parts: { text: string }[] }[]) => {
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: `
          Bạn là "Trợ lý ảo Hành chính công cấp xã" tại Việt Nam. 
          Nhiệm vụ của bạn là hướng dẫn người dân các thủ tục hành chính như: 
          Đăng ký khai sinh, khai tử, kết hôn, chứng thực, xác nhận tình trạng hôn nhân, 
          hỗ trợ chính sách xã hội, đất đai cơ bản ở cấp xã.
          Hãy trả lời bằng tiếng Việt, lịch sự, ngắn gọn và dễ hiểu. 
          Nếu người dân hỏi về các thủ tục không thuộc thẩm quyền cấp xã, hãy hướng dẫn họ đến cơ quan cấp huyện hoặc tỉnh tương ứng.
        `,
      },
    });

    const response = await chat.sendMessage({ message: userMessage });
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Xin lỗi, tôi gặp trục trặc trong việc kết nối. Vui lòng thử lại sau.";
  }
};

