import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Interface for chat history item.
 */
interface HistoryItem {
  role: 'user' | 'model';
  parts: { text: string }[];
}

/**
 * Handles communication with Gemini API for the administrative assistant chatbot.
 * @param userMessage The current user input message.
 * @param history The conversation history to maintain context.
 */
export const getGeminiChatResponse = async (userMessage: string, history: HistoryItem[]) => {
  try {
    // Initializing the chat session with the provided history
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      history: history,
      config: {
        systemInstruction: `
          Bạn là "Trợ lý ảo Hành chính công cấp xã" tại Việt Nam. 
          Nhiệm vụ của bạn là hướng dẫn người dân các thủ tục hành chính như: 
          Đăng ký khai sinh, khai tử, kết hôn, chứng thực, xác nhận tình trạng hôn nhân, 
          hỗ trợ chính sách xã hội, đất đai cơ bản ở cấp xã.
          Hãy trả lời bằng tiếng Việt, lịch sự, ngắn gọn và dễ hiểu. 
          Nếu người dân hỏi về các thủ tục không thuộc thẩm quyền cấp xã, hãy hướng dẫn họ đến cơ quan cấp huyện hoặc tỉnh tương ứng.
        `,
      },
    });

    // sendMessage automatically appends the userMessage to the conversation and returns the response
    const response: GenerateContentResponse = await chat.sendMessage({ message: userMessage });

    // Accessing .text property directly as per Gemini API guidelines (do not use .text())
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Xin lỗi, tôi gặp trục trặc trong việc kết nối. Vui lòng thử lại sau.";
  }
};

