export class GeminiService {
  // Following guidelines: initialize GoogleGenAI right before the API call to use the latest API_KEY
  async sendMessage(history: Message[], userInput: string) {
    try {
      // Use process.env.API_KEY directly as required
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            ...history.map(m => ({
              text: `${m.role === 'model' ? 'Assistant:' : 'User:'} ${m.text}`
            })),
            { text: userInput }
          ]
        },
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          temperature: 0.2, 
          topP: 0.8,
        },
      });

      // Directly access .text property from GenerateContentResponse
      return response.text;
    } catch (error) {
      console.error("Gemini API Error:", error);
      throw error;
    }
  }
}

